// NODE 02: Felder aus eigenem Fragebogen lesen + Normierung (post-Tally)
const body = $input.item.json.body;

const dedupArr = (val) => {
  const arr = Array.isArray(val) ? val : [val].filter(Boolean);
  return [...new Set(arr)];
};

const raw = {
  partner_id:             body.partner_id || 'DEFAULT',
  first_name:             body.first_name || '',
  email:                  body.email || '',
  phone:                  body.phone || '',
  scalp_status:           dedupArr(body.scalp_status),
  hair_structure:         body.hair_structure || 'glatt',
  hair_thickness:         body.hair_thickness || 'mittel',
  hair_condition:         dedupArr(body.hair_condition),
  ends_condition:         body.ends_condition || null,
  hair_treatments:        body.hair_treatments || 'nein',
  heat_frequency:         body.heat_frequency || 'nie_selten',
  heat_tools:             dedupArr(body.heat_tools),
  wash_frequency:         body.wash_frequency || 'alle_2_3_tage',
  styling_effort:         body.styling_effort || 'leichtes_styling',
  curl_priority:          body.curl_priority || null,
  care_goals:             dedupArr(body.care_goals),
  routine_preference:     body.routine_preference || 'ausgewogen',
  time_commitment:        body.time_commitment || 'mittel',
  consent_recommendation: body.consent_recommendation === true || body.consent_recommendation === 'true',
  consent_marketing:      body.consent_marketing === true || body.consent_marketing === 'true',
};

return [{ json: { normalized: raw, raw_input: raw, partner_id: raw.partner_id } }];

// NODE 04 v2: Prioritäten auflösen — Regeln aus DB
// ===================================================
// Bestimmt primary_scalp_state und primary_hair_condition.
// Prioritäts-Reihenfolge stammt aus map_priorities (Sheet),
// kein Inline-Array mehr im Code.
//
// VORAUSSETZUNG: Node 04a Prioritäten laden muss im Workflow
// vor Node 04 ausgeführt werden (Verkabelung 03 → 04a → 04).
// ===================================================

const profile = $node["02 Felder extrahieren"].json;
const n = profile.normalized || profile;

// Regeln aus DB laden
const priorityRules = $items("04a Prioritäten laden")
  .map(it => it.json)
  .filter(r => String(r.aktiv).toUpperCase() === 'TRUE');

function buildPriority(kategorie) {
  return priorityRules
    .filter(r => r.kategorie === kategorie)
    .sort((a, b) => (parseInt(a.reihenfolge) || 999) - (parseInt(b.reihenfolge) || 999))
    .map(r => r.wert);
}

const SCALP_PRIORITY     = buildPriority('scalp');
const CONDITION_PRIORITY = buildPriority('condition');

function prioritize(arr, priorityList) {
  if (!arr || arr.length === 0) return { primary: null, secondary: [] };
  const sorted = [...arr].sort((a, b) => {
    const ia = priorityList.indexOf(a);
    const ib = priorityList.indexOf(b);
    return (ia === -1 ? 99 : ia) - (ib === -1 ? 99 : ib);
  });
  return {
    primary: sorted[0],
    secondary: sorted.slice(1, 2)
  };
}

const scalpArr = Array.isArray(n.scalp_status) ? n.scalp_status : [n.scalp_status].filter(Boolean);
const condArr  = Array.isArray(n.hair_condition) ? n.hair_condition : [n.hair_condition].filter(Boolean);

const scalpResult = prioritize(scalpArr, SCALP_PRIORITY);
const conditionResult = prioritize(
  condArr.filter(c => c !== 'keine_probleme'),
  CONDITION_PRIORITY
);

const conditionCleaned = condArr.filter(c => c !== 'keine_probleme').length > 0
  ? condArr.filter(c => c !== 'keine_probleme')
  : ['keine_probleme'];

const priorities = {
  primary_scalp_state:       scalpResult.primary || 'normal',
  secondary_scalp_states:    scalpResult.secondary,
  primary_hair_condition:    conditionResult.primary || 'keine_probleme',
  secondary_hair_conditions: conditionResult.secondary,
  hair_condition_cleaned:    conditionCleaned
};

return [{ json: { normalized: n, priorities } }];

// NODE 05 v2: Bool-Flags aus map_derived_variables auswerten
// ===========================================================
// Ersetzt 76 LOC Inline-Heuristiken durch generischen JSON-Regel-
// Evaluator. Regeln stammen aus Sheet 'map_derived_variables'
// (Spalten: variable, typ, regel_json, erlaubte_werte, konsumenten, doku).
//
// Sheet-Reihenfolge = Auswertungs-Reihenfolge.
// Phase 1 (R02-R14): nur normalized.* Refs
// Phase 2 (R15-R18): zusätzlich flags.* Refs
//
// VORAUSSETZUNG: Node 05a 'map_derived_variables laden' muss
// vor Node 05 ausgeführt werden (Verkabelung 04 → 05a → 05).
// ===========================================================

const item = $node["04 Prioritäten auflösen"].json;
const n = item.normalized;
const p = item.priorities;

const sheetRows = $items("05a map_derived_variables laden")
  .map(it => it.json)
  .filter(r => r.variable && r.regel_json);

function resolveRef(path, ctx) {
  const parts = path.split(".");
  const src = parts.shift();
  const root = src === "flags" ? ctx.flags
             : src === "normalized" ? ctx.normalized
             : src === "priorities" ? ctx.priorities
             : null;
  if (root === null) throw new Error(`Unknown ref source: ${src} (path: ${path})`);
  return parts.reduce((acc, k) => (acc == null ? acc : acc[k]), root);
}

function evalExpr(expr, ctx) {
  if (expr === true || expr === false) return expr;
  if (expr == null) throw new Error("null/undefined expression");
  const op = Object.keys(expr)[0];
  const v = expr[op];
  switch (op) {
    case "eq":  return resolveRef(v[0], ctx) === v[1];
    case "neq": return resolveRef(v[0], ctx) !== v[1];
    case "in":  return v[1].includes(resolveRef(v[0], ctx));
    case "nin": return !v[1].includes(resolveRef(v[0], ctx));
    case "includes": {
      const arr = resolveRef(v[0], ctx);
      return Array.isArray(arr) && arr.includes(v[1]);
    }
    case "intersects": {
      const arr = resolveRef(v[0], ctx);
      return Array.isArray(arr) && arr.some(x => v[1].includes(x));
    }
    case "truthy": {
      const x = resolveRef(v, ctx);
      return x !== undefined && x !== null && x !== "" && x !== false;
    }
    case "and": return v.every(e => evalExpr(e, ctx));
    case "or":  return v.some(e => evalExpr(e, ctx));
    case "not": return !evalExpr(v, ctx);
    default: throw new Error(`Unknown operator: ${op}`);
  }
}

function evalRule(rule, ctx) {
  if (rule.cases) {
    for (const c of rule.cases) {
      if (evalExpr(c.when, ctx)) return c.then;
    }
    return rule.else;
  }
  return evalExpr(rule, ctx);
}

const flags = {};
const ctx = { normalized: n, priorities: p, flags };

for (const row of sheetRows) {
  let rule;
  try {
    rule = JSON.parse(row.regel_json);
  } catch (e) {
    throw new Error(`map_derived_variables.${row.variable}: regel_json parse error: ${e.message}`);
  }
  try {
    flags[row.variable] = evalRule(rule, ctx);
  } catch (e) {
    throw new Error(`map_derived_variables.${row.variable}: eval error: ${e.message}`);
  }
}

return [{ json: { normalized: n, priorities: p, flags } }];

// ============================================================
// NODE 06 v3: Pflegelevel berechnen — Regeln aus DB
// ============================================================
// Architektur-Prinzip: Tabelle = Wahrheit, Node = Auswerter.
// Punktevergabe-Regeln stehen in map_pflegelevel_scoring.
// Floor, Cap, Schwellen und max_products bleiben im Code,
// weil das System-Parameter sind, keine fachlichen Regeln.
//
// VORAUSSETZUNG: Node 06a Pflegelevel-Scoring laden muss im
// Workflow vor Node 06 ausgeführt werden (Verkabelung:
// 05 → 06a → 06).
// ============================================================

// Profildaten aus Node 05 holen (analog zu Node 14 → Node 11)
const profile = $node["05 Bool-Flags berechnen"].json;
const n = profile.normalized;
const p = profile.priorities;
const f = profile.flags;

// Regeln aus DB laden (über $items aus 06a)
const scoringRules = $items("06a Pflegelevel-Scoring laden")
  .map(it => it.json)
  .filter(r => String(r.aktiv).toUpperCase() === 'TRUE');

// ── Helpers ──

function evalBedingung(rule) {
  const feld = rule.bedingung_feld;
  const wert = String(rule.bedingung_wert || '').trim();
  const typ  = String(rule.bedingung_typ || '').trim();

  const fieldValue = n[feld];

  if (typ === 'array_contains') {
    if (!Array.isArray(fieldValue)) return false;
    return fieldValue.includes(wert);
  }

  if (typ === 'equals') {
    return String(fieldValue || '').toLowerCase() === wert.toLowerCase();
  }

  if (typ === 'in_list') {
    const allowed = wert.split('|').map(s => s.trim().toLowerCase());
    return allowed.includes(String(fieldValue || '').toLowerCase());
  }

  return false;
}

// ── Phase 1: Regel-basierte Punkte aus DB ──

let pts = 0;
const firedRules = [];

// Spezialbehandlung: PFL-02/03 (haarbruch/spliss) sollen NICHT zusätzlich
// zu PFL-01 (stark_geschaedigt) feuern — Code-Logik: else if
const hasStarkGesch = (n.hair_condition || []).includes('stark_geschaedigt');

for (const rule of scoringRules) {
  // Skip haarbruch/spliss-Punkte wenn stark_geschaedigt bereits zählt
  if (hasStarkGesch && ['PFL-02', 'PFL-03'].includes(rule.regel_id)) continue;

  if (evalBedingung(rule)) {
    const punkte = parseInt(rule.punkte) || 0;
    pts += punkte;
    firedRules.push({
      regel_id: rule.regel_id,
      kategorie: rule.kategorie,
      punkte: punkte
    });
  }
}

// ── Phase 2: Ziele-Berechnung (Code, weil dynamisch) ──
// Bis zu 2 Punkte für nicht-kopfhaut-Pflegeziele
const cg = n.care_goals || [];
const goalCount = cg.filter(g => g !== 'gesunde_kopfhaut').length;
const goalPts = Math.min(goalCount, 2);
pts += goalPts;
if (goalPts > 0) {
  firedRules.push({
    regel_id: 'PFL-ZIELE',
    kategorie: 'ziele',
    punkte: goalPts,
    note: `${goalCount} Ziele (max 2)`
  });
}

// ── Phase 3: Rohlevel (LOW/MID/HIGH Schwellen) ──
// System-Parameter, kein fachlicher Regel-Inhalt
let level    = pts <= 3 ? 'LOW' : pts <= 7 ? 'MID' : 'HIGH';
let levelNum = level === 'LOW' ? 1 : level === 'MID' ? 2 : 3;

// ── Phase 4 + 5: Override-Regeln aus map_pflegelevel_overrides ──
// Tabelle = Wahrheit. raise_to setzt Floor, cap_at setzt Ceiling.
// Else-If-Semantik via prioritaet (erste passende raise-Regel stoppt die Kette).
// Cap-Regeln greifen nur, wenn keine raise-Regel gematcht hat (auch ohne Update).

const overrideRules = $items("06b Pflegelevel-Overrides laden")
  .map(it => it.json)
  .filter(r => String(r.aktiv).toUpperCase() === 'TRUE');

const LEVEL_TO_NUM = { LOW: 1, MID: 2, HIGH: 3 };
const NUM_TO_LEVEL = { 1: 'LOW', 2: 'MID', 3: 'HIGH' };

function evalSingleCondition(profileObj, feld, typ, wert) {
  if (!feld || !typ) return true;
  const val = profileObj[feld];
  const w = String(wert == null ? '' : wert);
  const t = String(typ).toLowerCase().trim();
  switch (t) {
    case 'equals':
      return String(val == null ? '' : val).toLowerCase() === w.toLowerCase();
    case 'in_list':
      return w.split('|').map(s => s.trim().toLowerCase())
        .includes(String(val == null ? '' : val).toLowerCase());
    case 'array_contains':
      return Array.isArray(val) && val.includes(w);
    default:
      return false;
  }
}

function evalOverrideRule(rule, profileObj) {
  if (!evalSingleCondition(profileObj, rule.bedingung1_feld, rule.bedingung1_typ, rule.bedingung1_wert)) return false;
  if (!evalSingleCondition(profileObj, rule.bedingung2_feld, rule.bedingung2_typ, rule.bedingung2_wert)) return false;
  return true;
}

// raise_to in prioritaet-Reihenfolge, erste passende Regel stoppt die Kette
const raiseRules = overrideRules
  .filter(r => String(r.aktion).toLowerCase() === 'raise_to')
  .sort((a, b) => (parseInt(a.prioritaet) || 999) - (parseInt(b.prioritaet) || 999));

let raiseMatched = null;
for (const rule of raiseRules) {
  if (evalOverrideRule(rule, n)) {
    raiseMatched = rule.regel_id;
    const target = LEVEL_TO_NUM[String(rule.ziel_level).toUpperCase()];
    if (target && levelNum < target) {
      levelNum = target;
      level = NUM_TO_LEVEL[target];
      firedRules.push({
        regel_id: rule.regel_id,
        kategorie: 'override_floor',
        ziel_level: rule.ziel_level
      });
    }
    break;
  }
}

// cap_at — nur wenn keine raise-Regel gematcht hat
const rp = n.routine_preference;
if (!raiseMatched) {
  const capRules = overrideRules.filter(r => String(r.aktion).toLowerCase() === 'cap_at');
  for (const rule of capRules) {
    if (evalOverrideRule(rule, n)) {
      const target = LEVEL_TO_NUM[String(rule.ziel_level).toUpperCase()];
      if (target && levelNum > target) {
        levelNum = target;
        level = NUM_TO_LEVEL[target];
        firedRules.push({
          regel_id: rule.regel_id,
          kategorie: 'override_cap',
          ziel_level: rule.ziel_level
        });
      }
    }
  }
}

// ── Phase 6: Max Products aus map_max_products ──
// Tabelle = Wahrheit. 2D-Lookup (routine_preference × pflegelevel) → max_products.
const maxRules = $items("06c Max-Products laden")
  .map(it => it.json)
  .filter(r => String(r.aktiv).toUpperCase() === 'TRUE');

let maxProducts = 7; // Safety-Default falls keine Regel matched
for (const rule of maxRules) {
  const sameRp    = String(rule.routine_preference).toLowerCase() === String(rp).toLowerCase();
  const sameLevel = String(rule.pflegelevel).toUpperCase() === String(level).toUpperCase();
  if (sameRp && sameLevel) {
    maxProducts = parseInt(rule.max_products) || 7;
    break;
  }
}

const pflegelevel = {
  pflegelevel_raw:     pts,
  pflegelevel_final:   level,
  pflegelevel_numeric: levelNum,
  max_products:        maxProducts,
  routine_preference:  rp,
  fired_rules:         firedRules
};

return [{ json: {
  normalized: n,
  priorities: p,
  flags: f,
  pflegelevel
}}];

// NODE 08: Ausschluss-Filter anwenden (v2: Sheet-getriebene Pool-Filter)
//
// Architektur-Prinzip: Tabelle = Wahrheit, Node = Auswerter.
// Pool-Filter-Regeln stehen in map_pool_filter (Loader 08a).
// Andere Filter (ausschluss_bei, haarstaerke, pflegelevel) sind Spalten
// der Produktdatenbank und damit pro-Produkt konfigurierbar.
//
// VORAUSSETZUNG: 08a Pool-Filter laden läuft vor Node 08 (07 → 08a → 08).

const profile = $node["06 Pflegelevel berechnen"].json;
const n  = profile.normalized;
const f  = profile.flags;
const pl = profile.pflegelevel;
const p  = profile.priorities;

// Produkte explizit aus Node 07 holen (08a liegt direkt davor im main-Strom)
const allProducts = $items("07 Produktdatenbank laden").map(it => it.json);

// Pool-Filter-Regeln aus Sheet (nur aktive, nach Priorität sortiert)
const poolRules = $items("08a Pool-Filter laden")
  .map(it => it.json)
  .filter(r => String(r.aktiv).toUpperCase() === 'TRUE')
  .sort((a, b) => Number(a.prioritaet || 0) - Number(b.prioritaet || 0));

function csvToArr(val) {
  if (!val || val === '-' || val === '') return [];
  return val.split(',').map(v => v.trim().toLowerCase());
}

function boolVal(v) { return String(v).toUpperCase() === 'TRUE'; }

// Profil-Pfad-Auflösung: "flags.needs_repair_focus" -> profile.flags.needs_repair_focus
function resolveProfilePath(path) {
  const parts = String(path).split('.');
  let cur = profile;
  for (const part of parts) {
    if (cur == null) return undefined;
    cur = cur[part];
  }
  return cur;
}

// Bedingung "feld:op[:wert]" auswerten
// kind = 'profile' (Profilpfad) oder 'product' (prod[feld])
function evalCondition(condStr, prod, kind) {
  const m = String(condStr).match(/^([^:]+):([a-z_=!]+)(?::(.*))?$/i);
  if (!m) return false;
  const field = m[1];
  const op = m[2];
  const rawVal = m[3];
  const lhs = kind === 'profile' ? resolveProfilePath(field) : prod[field];
  const lower = (v) => v == null ? '' : String(v).toLowerCase();

  switch (op) {
    case 'is_true':  return boolVal(lhs);
    case 'is_false': return !boolVal(lhs);
    case '=':        return lower(lhs) === lower(rawVal);
    case '!=':       return lower(lhs) !== lower(rawVal);
    case 'in': {
      const list = (rawVal || '').split('|').map(s => s.trim().toLowerCase());
      if (Array.isArray(lhs)) return lhs.some(v => list.includes(lower(v)));
      return list.includes(lower(lhs));
    }
    case 'not_in': {
      const list = (rawVal || '').split('|').map(s => s.trim().toLowerCase());
      if (Array.isArray(lhs)) return !lhs.some(v => list.includes(lower(v)));
      return !list.includes(lower(lhs));
    }
    default: return false;
  }
}

// Bedingungs-String "c1;c2;c3" -> Array (alle UND-verknüpft)
function parseConditions(s) {
  if (!s || String(s).trim() === '' || String(s).trim() === '-') return [];
  return String(s).split(';').map(c => c.trim()).filter(Boolean);
}

// Pool-Regel matched, wenn ALLE Profil- UND ALLE Produkt-Bedingungen erfüllt sind
function poolRuleMatches(rule, prod) {
  for (const c of parseConditions(rule.profil_bedingungen)) {
    if (!evalCondition(c, prod, 'profile')) return false;
  }
  for (const c of parseConditions(rule.produkt_bedingungen)) {
    if (!evalCondition(c, prod, 'product')) return false;
  }
  return true;
}

const filtered = allProducts.filter(prod => {
  if (!boolVal(prod.aktiv)) return false;
  if (!prod.produkt_key) return false;

  const ausschluss  = csvToArr(prod.ausschluss_bei);
  const pflegelev   = csvToArr(prod.pflegelevel);
  const haarstaerke = csvToArr(prod.haarstaerke);

  // 1. ausschluss_bei (Datenblatt-getrieben über Produktspalte)
  const profileValues = [
    ...(Array.isArray(n.scalp_status) ? n.scalp_status : [n.scalp_status]),
    ...(Array.isArray(n.hair_condition) ? n.hair_condition : [n.hair_condition]),
    n.hair_structure,
    n.hair_treatments
  ].filter(Boolean).map(v => v.toLowerCase());

  for (const excl of ausschluss) {
    if (profileValues.includes(excl)) return false;
  }

  // 2. haarstaerke-Filter (Datenblatt-getrieben)
  if (haarstaerke.length > 0 && !haarstaerke.includes('alle')) {
    if (!haarstaerke.includes(n.hair_thickness.toLowerCase())) return false;
  }

  // 3. Pool-Filter-Regeln (map_pool_filter)
  for (const rule of poolRules) {
    if (poolRuleMatches(rule, prod)) return false;
  }

  // 4. pflegelevel-Kompatibilität (Datenblatt-getrieben)
  if (pflegelev.length > 0
      && !pflegelev.includes(pl.pflegelevel_final.toLowerCase())) {
    return false;
  }

  return true;
});

return [{ json: {
  normalized: n,
  priorities: p,
  flags: f,
  pflegelevel: pl,
  filtered_pool: filtered
}}];

// NODE 09: Pool validieren
const data = $input.item.json;
const pool = data.filtered_pool;

const warnings = [];
const stats = {};

// Zähle Kandidaten je Slot
const slotTypes = ['shampoo','spuelung','maske','kopfhaut','leave_in','styling_1','styling_2','finish'];
for (const slot of slotTypes) {
  stats[slot] = pool.filter(p => p.slot_typ === slot).length;
  if (stats[slot] === 0) warnings.push(`WARNUNG: Kein Kandidat für Slot ${slot}`);
}

// Fallback: Wenn kein Shampoo → Renew Shampoo als Fallback
if (stats['shampoo'] === 0) {
  warnings.push('KRITISCH: Kein Shampoo-Kandidat – Fallback auf Renew Shampoo');
}

return [{ json: {
  ...data,
  pool_stats: stats,
  warnings
}}];

// NODE 11: REQ-Regeln vollständig deklarativ aus map_slot_rules
// =============================================================
// Liest alle Slot-Regeln aus dem Google Sheet "map_slot_rules".
// KEINE Regel mehr im Code. Tabelle = Wahrheit, Node = Auswerter.
//
// Tabellenspalten:
//   regel_id | slot_typ | prioritaet
//   | trigger_flag  | trigger_wert     ← Hauptbedingung
//   | trigger_flag2 | trigger_wert2    ← UND-Verknüpfung (optional)
//   | overrides                        ← regel_id(s) die ersetzt werden (CSV)
//   | requires_not                     ← Regel feuert nur wenn diese regel_id(s) NICHT gefeuert haben (CSV)
//   | filter | reason | aktiv
//
// trigger_wert Syntax:
//   - "TRUE" / "FALSE"      → Boolean
//   - "yes" / "stark_..."   → String exakt
//   - "schuppig|fettig"     → ODER (mehrere erlaubte Werte)
//   - ">=2", ">3", "=1"     → Numerischer Vergleich
//   - hair_condition_contains + Wert → Array-Inklusion in n.hair_condition
//
// requires_not wird in zweiter Phase aufgelöst (nachdem alle anderen
// Regeln evaluiert wurden), damit Reihenfolge in der Tabelle egal ist.
// =============================================================

const profile = $node["08 Ausschluss-Filter"].json;
const n   = profile.normalized;
const f   = profile.flags;
const pl  = profile.pflegelevel;
const p   = profile.priorities;
const pool = profile.filtered_pool;

const ruleItems = $items("10 map_slot_rules");
const rules = ruleItems
  .map(it => it.json)
  .filter(r => String(r.aktiv).toUpperCase() === 'TRUE');

// ── Helpers ─────────────────────────────────────────────────

function normStr(v) {
  return v === undefined || v === null ? '' : String(v).trim();
}

function getFlagValue(flagName) {
  if (flagName in f)  return f[flagName];
  if (flagName in n)  return n[flagName];
  if (flagName in pl) return pl[flagName];
  if (flagName in p)  return p[flagName];
  return undefined;
}

function evalSingleTrigger(flag, wert) {
  flag = normStr(flag);
  wert = normStr(wert);
  if (flag === '') return true; // leer = immer wahr

  if (flag === 'hair_condition_contains') {
    return Array.isArray(n.hair_condition) && n.hair_condition.includes(wert);
  }

  const val = getFlagValue(flag);
  if (val === undefined) return false;

  // Numerischer Vergleich
  const numMatch = wert.match(/^(>=|<=|>|<|=)\s*(-?\d+(?:\.\d+)?)$/);
  if (numMatch) {
    const op = numMatch[1], num = parseFloat(numMatch[2]);
    const v = parseFloat(val);
    if (isNaN(v)) return false;
    switch (op) {
      case '>=': return v >= num;
      case '<=': return v <= num;
      case '>':  return v >  num;
      case '<':  return v <  num;
      case '=':  return v === num;
    }
  }

  // ODER-Liste
  if (wert.includes('|')) {
    const allowed = wert.split('|').map(s => s.trim().toLowerCase());
    return allowed.includes(String(val).toLowerCase());
  }

  // Boolean
  const wU = wert.toUpperCase();
  if (wU === 'TRUE')  return val === true  || String(val).toUpperCase() === 'TRUE';
  if (wU === 'FALSE') return val === false || String(val).toUpperCase() === 'FALSE';

  // String exakt (case-insensitive)
  return String(val).toLowerCase() === wert.toLowerCase();
}

function evalRule(r) {
  // UND-Verknüpfung beider Trigger
  if (!evalSingleTrigger(r.trigger_flag,  r.trigger_wert))  return false;
  if (!evalSingleTrigger(r.trigger_flag2, r.trigger_wert2)) return false;
  return true;
}

function csvList(v) {
  return normStr(v).split(',').map(s => s.trim()).filter(Boolean);
}

// ── Phase 1: Welche Regeln feuern grundsätzlich? ────────────

const firedIds = new Set();
const firedByRule = {};

for (const r of rules) {
  if (evalRule(r)) {
    firedIds.add(r.regel_id);
    firedByRule[r.regel_id] = r;
  }
}

// ── Phase 2: requires_not auflösen ─────────────────────────
//    Regel verwerfen wenn eine ihrer requires_not-IDs gefeuert hat.

const finalFired = new Set();
for (const id of firedIds) {
  const r = firedByRule[id];
  const blockedBy = csvList(r.requires_not);
  const isBlocked = blockedBy.some(bid => firedIds.has(bid));
  if (!isBlocked) finalFired.add(id);
}

// ── Phase 3: overrides auflösen ────────────────────────────
//    Wenn Regel X overrides=Y enthält, wird Y aus finalFired entfernt.

const overridden = new Set();
for (const id of finalFired) {
  const r = firedByRule[id];
  for (const oid of csvList(r.overrides)) overridden.add(oid);
}
for (const oid of overridden) finalFired.delete(oid);

// ── Phase 4: Slot-Assignments bauen ────────────────────────

const slots = {
  required_always:      [],
  required_conditional: [],
  optional:             [],
  disabled:             []
};

// Reihenfolge wie in Tabelle erhalten
for (const r of rules) {
  if (!finalFired.has(r.regel_id)) continue;

  const entry = {
    slot_typ: normStr(r.slot_typ),
    filter:   normStr(r.filter),
    reason:   `${r.regel_id}: ${r.reason || ''}`.trim()
  };

  const prio = normStr(r.prioritaet);
  if (prio === 'required_always')           slots.required_always.push(entry);
  else if (prio === 'required_conditional') slots.required_conditional.push(entry);
  else if (prio === 'optional')             slots.optional.push(entry);
}

// ── Suppress bei routine_preference=minimal ────────────────
if (n.routine_preference === 'minimal') {
  slots.optional = [];
}

return [{ json: {
  normalized:       n,
  priorities:       p,
  flags:            f,
  pflegelevel:      pl,
  filtered_pool:    pool,
  slot_assignments: slots,
  applied_rules:    Array.from(finalFired)
}}];

// NODE 12 v4: Slot-Befüllung via 11-Stufen-Ranking-Hierarchie
// ============================================================
// Erweitert v3 (10 Stufen) um Stufe 11 (intensitaetMatch).
// Stufe 11 löst die letzten 5 alphabetischen Ties durch
// Pflege-Intensitäts-Match (Sheet-Spalte `intensitaet`,
// Profil-Heuristik `wants_intense_care` aus Node 05).
//
// Reihenfolge:
//   1.  hauptfunktion
//   2.  haarzustand-primary
//   3.  goal_coverage
//   4.  scalp_match
//   5.  curl_compat
//   6.  haarstruktur-exakt
//   7.  pflegelev_match
//   8.  haarstaerke-exakt
//   9.  haarzustand-coverage
//   10. Wildcard-Akzeptanz (haarstruktur+haarstaerke 'alle')
//   11. intensitaet-Match            NEU
//   (Fallback: produkt_key.localeCompare — sollte nicht mehr greifen)
// ============================================================

const data = $input.item.json;
const n    = data.normalized;
const f    = data.flags;
const pl   = data.pflegelevel;
const p    = data.priorities;
const pool = data.filtered_pool;
const slots = data.slot_assignments;
const appliedRules = data.applied_conflict_rules || [];

const profilMapping = $items("06d Profil-Funktion-Mapping laden")
  .map(it => it.json)
  .filter(r => String(r.aktiv).toUpperCase() === 'TRUE');

function boolVal(v) { return String(v).toUpperCase() === 'TRUE'; }
function csvToArr(v) {
  if (!v || v === '-' || v === '') return [];
  return v.split(',').map(s => s.trim().toLowerCase());
}

function mapProfileToFunction(feld, wert) {
  if (!wert) return null;
  const row = profilMapping.find(r =>
    String(r.profil_feld).trim() === feld &&
    String(r.profil_wert).trim() === String(wert).trim()
  );
  const token = row ? String(row.funktions_token || '').trim() : '';
  return token || null;
}

const primaryHF = mapProfileToFunction('hair_condition', p.primary_hair_condition);
const wantsIntense = f.wants_intense_care === true;

function profileProduct(prod) {
  const hauptfunktionen = csvToArr(prod.hauptfunktion);
  const nebenfunktionen = csvToArr(prod.nebenfunktionen);
  const kopfhaut        = csvToArr(prod.kopfhaut);
  const pflegelev       = csvToArr(prod.pflegelevel);
  const haarzustand     = csvToArr(prod.haarzustand);
  const haarstruktur    = csvToArr(prod.haarstruktur);
  const haarstaerke     = csvToArr(prod.haarstaerke);
  const allFunktionen   = [...hauptfunktionen, ...nebenfunktionen];

  const hfMatch = (primaryHF && hauptfunktionen.includes(primaryHF)) ? 1 : 0;

  const primaryHC = p.primary_hair_condition;
  const hzPrimaryMatch = (primaryHC && primaryHC !== 'keine_probleme'
                          && haarzustand.includes(primaryHC)) ? 1 : 0;

  const goalCount = (n.care_goals || [])
    .filter(g => allFunktionen.includes(String(g).toLowerCase()))
    .length;

  const scalpMatch = kopfhaut.includes(p.primary_scalp_state) ? 1 : 0;

  const curlMatch = (f.needs_curl_care && boolVal(prod.locken_geeignet)) ? 1 : 0;

  const hairStructure = n.hair_structure;
  const hsExactMatch = (hairStructure && haarstruktur.includes(hairStructure)) ? 1 : 0;

  const plMatch = pflegelev.includes(String(pl.pflegelevel_final || '').toLowerCase()) ? 1 : 0;

  const hairThickness = n.hair_thickness;
  const hkExactMatch = (hairThickness && haarstaerke.includes(hairThickness)) ? 1 : 0;

  const cleaned = (p.hair_condition_cleaned || [])
    .map(c => String(c).toLowerCase())
    .filter(c => c !== 'keine_probleme');
  const hzCoverage = cleaned.filter(c => haarzustand.includes(c)).length;

  const allMatch = (haarstruktur.includes('alle') ? 1 : 0)
                 + (haarstaerke.includes('alle') ? 1 : 0);

  // Stufe 11: intensitaet-Match
  // Sheet-Werte: 'leicht' / 'intensiv' / 'alle' (Default).
  // wants_intense_care === true  : prefer 'intensiv' (2), 'alle' neutral (1), 'leicht' gegenteilig (0)
  // wants_intense_care === false : prefer 'leicht'   (2), 'alle' neutral (1), 'intensiv' gegenteilig (0)
  const prodIntens = String(prod.intensitaet || 'alle').trim().toLowerCase() || 'alle';
  let intensMatch;
  if (prodIntens === 'alle') {
    intensMatch = 1;
  } else if (wantsIntense && prodIntens === 'intensiv') {
    intensMatch = 2;
  } else if (!wantsIntense && prodIntens === 'leicht') {
    intensMatch = 2;
  } else {
    intensMatch = 0;
  }

  return {
    hfMatch,
    hzPrimaryMatch,
    goalCount,
    scalpMatch,
    curlMatch,
    hsExactMatch,
    plMatch,
    hkExactMatch,
    hzCoverage,
    allMatch,
    intensMatch,
    breakerKey: prod.produkt_key || ''
  };
}

function cmpProfiles(a, b) {
  if (a.hfMatch         !== b.hfMatch)         return b.hfMatch         - a.hfMatch;
  if (a.hzPrimaryMatch  !== b.hzPrimaryMatch)  return b.hzPrimaryMatch  - a.hzPrimaryMatch;
  if (a.goalCount       !== b.goalCount)       return b.goalCount       - a.goalCount;
  if (a.scalpMatch      !== b.scalpMatch)      return b.scalpMatch      - a.scalpMatch;
  if (a.curlMatch       !== b.curlMatch)       return b.curlMatch       - a.curlMatch;
  if (a.hsExactMatch    !== b.hsExactMatch)    return b.hsExactMatch    - a.hsExactMatch;
  if (a.plMatch         !== b.plMatch)         return b.plMatch         - a.plMatch;
  if (a.hkExactMatch    !== b.hkExactMatch)    return b.hkExactMatch    - a.hkExactMatch;
  if (a.hzCoverage      !== b.hzCoverage)      return b.hzCoverage      - a.hzCoverage;
  if (a.allMatch        !== b.allMatch)        return b.allMatch        - a.allMatch;
  if (a.intensMatch     !== b.intensMatch)     return b.intensMatch     - a.intensMatch;
  return a.breakerKey.localeCompare(b.breakerKey);
}

function findDecisionStage(winner, second) {
  if (!second) return 'alone';
  if (winner.hfMatch         !== second.hfMatch)         return 'Stufe 1 (hauptfunktion)';
  if (winner.hzPrimaryMatch  !== second.hzPrimaryMatch)  return 'Stufe 2 (haarzustand_primary)';
  if (winner.goalCount       !== second.goalCount)       return 'Stufe 3 (goal_coverage)';
  if (winner.scalpMatch      !== second.scalpMatch)      return 'Stufe 4 (scalp_match)';
  if (winner.curlMatch       !== second.curlMatch)       return 'Stufe 5 (curl_compat)';
  if (winner.hsExactMatch    !== second.hsExactMatch)    return 'Stufe 6 (haarstruktur_exakt)';
  if (winner.plMatch         !== second.plMatch)         return 'Stufe 7 (pflegelev_match)';
  if (winner.hkExactMatch    !== second.hkExactMatch)    return 'Stufe 8 (haarstaerke_exakt)';
  if (winner.hzCoverage      !== second.hzCoverage)      return 'Stufe 9 (haarzustand_coverage)';
  if (winner.allMatch        !== second.allMatch)        return 'Stufe 10 (wildcard_alle)';
  if (winner.intensMatch     !== second.intensMatch)     return 'Stufe 11 (intensitaet)';
  return 'Fallback (alphabetisch tie_breaker)';
}

const allSlotDefs = [
  ...slots.required_always.map(s => ({...s, priority: 'required_always'})),
  ...slots.required_conditional.map(s => ({...s, priority: 'required_conditional'})),
  ...slots.optional.map(s => ({...s, priority: 'optional'}))
];

const slot_winners = {};
const usedKeys = new Set();

for (const slotDef of allSlotDefs) {
  const slotType = slotDef.slot_typ;
  const filterStr = slotDef.filter || '';

  let candidates = pool.filter(prod => prod.slot_typ === slotType);

  if (filterStr && filterStr !== '') {
    const filters = filterStr.split('|');
    const filtered = candidates.filter(prod =>
      filters.some(fStr => {
        const flagMatch = fStr.match(/^([a-zA-Z_][a-zA-Z0-9_]*)=(TRUE|FALSE)$/);
        if (flagMatch) {
          const field = flagMatch[1];
          const expected = flagMatch[2] === 'TRUE';
          return boolVal(prod[field]) === expected;
        }
        return prod.produkt_key?.includes(fStr)
            || prod.produktlinie?.includes(fStr)
            || prod.hauptfunktion?.includes(fStr);
      })
    );
    if (filtered.length > 0) candidates = filtered;
  }

  const available = candidates.filter(c => !usedKeys.has(c.produkt_key));
  if (available.length === 0) continue;

  const ranked = available.map(prod => ({ prod, profile: profileProduct(prod) }));
  ranked.sort((a, b) => cmpProfiles(a.profile, b.profile));

  const winner = ranked[0];
  const second = ranked[1] || null;
  const slotKey = `${slotType}_${slotDef.priority}`;

  if (!slot_winners[slotKey]) {
    slot_winners[slotKey] = {
      slot_typ:        slotType,
      priority:        slotDef.priority,
      reason:          slotDef.reason,
      produkt_key:     winner.prod.produkt_key,
      produktname_de:  winner.prod.produktname_de,
      produktlinie:    winner.prod.produktlinie || '',
      routine_schritt: parseInt(winner.prod.routine_schritt) || 99,
      profile:         winner.profile,
      decision_stage:  findDecisionStage(winner.profile, second ? second.profile : null),
      primary_hf_token: primaryHF || '(kein Mapping)',
      wants_intense:   wantsIntense,
      ranking_top5:    ranked.slice(0, 5).map(r => ({
        produkt_key: r.prod.produkt_key,
        ...r.profile
      })),
      anwendung:       winner.prod.anwendung || '',
      hauptfunktion:   winner.prod.hauptfunktion || ''
    };
    usedKeys.add(winner.prod.produkt_key);
  }
}

return [{ json: {
  normalized:      n,
  priorities:      p,
  flags:           f,
  pflegelevel:     pl,
  filtered_pool:   pool,
  slot_assignments: slots,
  slot_winners, applied_conflict_rules: appliedRules
}}];

// NODE 14: Konflikte auflösen – filtert Pool VOR Scoring
// =============================================================
// Liest map_conflict_rules aus Node 13 und reduziert den
// filtered_pool aus Node 11 – BEVOR Node 12 die Winner picked.
// Damit kann kein Slot leer bleiben.
// =============================================================

const profile = $node["11 REQ-Regeln auswerten"].json;
const n   = profile.normalized;
const f   = profile.flags;
const p   = profile.priorities;
const pl  = profile.pflegelevel;
const pool = profile.filtered_pool;
const slots = profile.slot_assignments;

// ── Slot-Prioritäten je slot_typ ermitteln ──
// Wenn ein slot_typ als required_always gilt, sind seine Produkte geschützt.
const slotPrioMap = {};
for (const s of (slots.required_always || []))      slotPrioMap[s.slot_typ] = 'required_always';
for (const s of (slots.required_conditional || [])) slotPrioMap[s.slot_typ] = slotPrioMap[s.slot_typ] || 'required_conditional';
for (const s of (slots.optional || []))             slotPrioMap[s.slot_typ] = slotPrioMap[s.slot_typ] || 'optional';

// ── Konfliktregeln laden ──
const rules = $items("13 Konfliktregeln laden").map(item => item.json);

// ── Helpers ──
function getProfileValue(flag) {
  if (flag in f) return f[flag];
  if (flag in p) return p[flag];
  if (flag in n) return n[flag];
  if (flag in pl) return pl[flag];
  return undefined;
}

function triggerMatches(flag, expected) {
  if (!flag || expected === undefined || expected === null || expected === '') return true;
  const actual = getProfileValue(flag);
  if (actual === undefined || actual === null) return false;

  const allowed = String(expected).split('|').map(s => s.trim());
  const norm = v => {
    if (v === true || v === 'TRUE' || v === 'true') return 'TRUE';
    if (v === false || v === 'FALSE' || v === 'false') return 'FALSE';
    return String(v);
  };
  const actualNorm = norm(actual);

  if (Array.isArray(actual)) {
    return allowed.some(a => actual.map(norm).includes(norm(a)));
  }
  return allowed.map(norm).includes(actualNorm);
}

function productMatches(prod, matchTyp, matchWert) {
  if (!matchTyp || !matchWert) return false;
  const werte = String(matchWert).split(',').map(s => s.trim());
  switch (matchTyp) {
    case 'produkt_key':  return werte.includes(prod.produkt_key);
    case 'produktlinie': return werte.includes(prod.produktlinie);
    case 'key_contains': return werte.some(w => prod.produkt_key?.includes(w));
    default: return false;
  }
}

// Bestimmt ob ein Produkt nach action entfernt werden soll.
// Slot-Priorität schützt ggf.
function shouldRemove(prod, action) {
  const slotPrio = slotPrioMap[prod.slot_typ] || 'optional';
  switch (action) {
    case 'exclude_product':
      return true;
    case 'exclude_unless_required':
      return slotPrio !== 'required_always';
    case 'suppress_optional':
      return slotPrio === 'optional';
    default:
      return false;
  }
}

// ── Pool filtern ──
let filteredPool = [...pool];
const appliedRules = [];

for (const rule of rules) {
  if (String(rule.aktiv).toUpperCase() !== 'TRUE') continue;

  const t1 = triggerMatches(rule.trigger_flag, rule.trigger_wert);
  const t2 = triggerMatches(rule.trigger_flag2, rule.trigger_wert2);
  if (!t1 || !t2) continue;

  const before = filteredPool.length;
  const removed = [];

  filteredPool = filteredPool.filter(prod => {
    if (productMatches(prod, rule.match_typ, rule.match_wert)) {
      if (shouldRemove(prod, rule.action)) {
        removed.push(prod.produkt_key);
        return false;
      }
    }
    return true;
  });

  if (before - filteredPool.length > 0) {
    appliedRules.push({
      konflikt_id: rule.konflikt_id,
      beschreibung: rule.beschreibung,
      removed_products: removed,
      removed_count: removed.length
    });
  }
}

return [{ json: {
  normalized: n,
  priorities: p,
  flags: f,
  pflegelevel: pl,
  filtered_pool: filteredPool,
  slot_assignments: slots,
  applied_conflict_rules: appliedRules
}}];

// NODE 15: Routine sortieren & begrenzen
// Liest slot_winners aus Node 12 (jetzt Vor-Node)

const data = $input.item.json;
const pl = data.pflegelevel;
const n  = data.normalized;
const slotWinners = data.slot_winners || {};

// slot_winners ist ein Objekt mit Slot-Keys → in Array umwandeln
const products = Object.values(slotWinners);

// Sortiere nach Priorität und routine_schritt
const priorityOrder = { 'required_always': 0, 'required_conditional': 1, 'optional': 2 };

products.sort((a, b) => {
  const pDiff = (priorityOrder[a.priority] || 2) - (priorityOrder[b.priority] || 2);
  if (pDiff !== 0) return pDiff;
  return (a.routine_schritt || 99) - (b.routine_schritt || 99);
});

// Produktlimit anwenden
const maxProd = pl.max_products;
const required = products.filter(p => p.priority !== 'optional');
const optional = products.filter(p => p.priority === 'optional');

let final = [...required];
for (const opt of optional) {
  if (final.length < maxProd) final.push(opt);
}

// Nach routine_schritt sortieren für Ausgabe
final.sort((a, b) => (a.routine_schritt || 99) - (b.routine_schritt || 99));

// Schritt-Nummer zuweisen
final = final.map((prod, idx) => ({
  ...prod,
  anwendungs_schritt: idx + 1
}));

// partner_id auf Top-Level
const partnerId = (n && n.partner_id) || data.partner_id || 'DEFAULT';

return [{ json: {
  ...data,
  final_routine: final,
  routine_count: final.length,
  partner_id: partnerId
}}];

// ============================================================
