function buildPriority(kategorie) {
  return priorityRules
    .filter(r => r.kategorie === kategorie)
    .sort((a, b) => (parseInt(a.reihenfolge) || 999) - (parseInt(b.reihenfolge) || 999))
    .map(r => r.wert);
}

const SCALP_PRIORITY     = buildPriority('scalp');
const CONDITION_PRIORITY = buildPriority('condition');

function prioritize(arr, priorityList) {
  if (!arr || arr.length === 0) return { primary: null, secondary: [] };
  const sorted = [...arr].sort((a, b) => {
    const ia = priorityList.indexOf(a);
    const ib = priorityList.indexOf(b);
    return (ia === -1 ? 99 : ia) - (ib === -1 ? 99 : ib);
  });
  return {
    primary: sorted[0],
    secondary: sorted.slice(1, 2)
  };
}

const scalpArr = Array.isArray(n.scalp_status) ? n.scalp_status : [n.scalp_status].filter(Boolean);
