// ── Helpers ──

function evalBedingung(rule) {
  const feld = rule.bedingung_feld;
  const wert = String(rule.bedingung_wert || '').trim();
  const typ  = String(rule.bedingung_typ || '').trim();

  const fieldValue = n[feld];

  if (typ === 'array_contains') {
    if (!Array.isArray(fieldValue)) return false;
    return fieldValue.includes(wert);
  }

  if (typ === 'equals') {
    return String(fieldValue || '').toLowerCase() === wert.toLowerCase();
  }

  if (typ === 'in_list') {
    const allowed = wert.split('|').map(s => s.trim().toLowerCase());
    return allowed.includes(String(fieldValue || '').toLowerCase());
  }

  return false;
}

